3_real_world_example.code:
const character1 = { name: 'Gimli', health: 100 };
const character2 = { name: 'Legolas', health: 100 };

function heal(amount) {
  this.health += amount;
  console.log(`${this.name} healed to ${this.health}`);
}

// We EXPLICITLY bind 'this' to character1, then execute immediately
heal.call(character1, 50); // 'Gimli healed to 150'

// We EXPLICITLY lock 'this' to character2 for later use
const healLegolas = heal.bind(character2);
healLegolas(20); // 'Legolas healed to 120'

6_edge_case.code:
function who() { console.log(this.name); }
const boundToA = who.bind({name: 'A'});
const boundToB = boundToA.bind({name: 'B'}); 
boundToB(); // Prints 'A'! First bind wins permanently.
